UPDATE TBL_INBOUND_PRODUCT SET INBOUND_STATUS = 'COMPLETED', ACTUAL_QUANTITY = CASE TBL_INBOUND_PRODUCT_ID
WHEN #{item.tblInboundProductId} THEN #{item.actualQuantity}
END, ACTUAL_DATE = CASE TBL_INBOUND_PRODUCT_ID
WHEN #{item.tblInboundProductId} THEN #{item.actualDate}
END, REMARKS = CASE TBL_INBOUND_PRODUCT_ID
WHEN #{item.tblInboundProductId} THEN #{item.remarks}
END, COMPLETE_TIME = GETDATE(), COMPLETE_USER = CASE TBL_INBOUND_PRODUCT_ID
WHEN #{item.tblInboundProductId} THEN #{item.completeUser}
END, UPDT_TIME = GETDATE(), UPDT_USER = CASE TBL_INBOUND_PRODUCT_ID
WHEN #{item.tblInboundProductId} THEN #{item.completeUser}
END WHERE TBL_INBOUND_PRODUCT_ID IN
#{item.tblInboundProductId}
AND INBOUND_STATUS = 'PENDING'

