SELECT ip.TBL_INBOUND_PRODUCT_ID as tblInboundProductId, ip.CMPY_CD as cmpyCd, ip.AGNT_CD as agntCd, a.AGNT_NM as agntNm, ip.MTRL_CD as mtrlCd, ip.MTRL_NM as mtrlNm, ip.TBL_MTRL_M_ID as tblMtrlMId, ip.INBOUND_QUANTITY as inboundQuantity, ip.INBOUND_STATUS as inboundStatus, ip.EXPECTED_DATE as expectedDate, ip.SAVE_TIME as saveTime, ip.SAVE_USER as saveUser, ip.UPDT_TIME as updtTime, ip.UPDT_USER as updtUser, ip.ACTUAL_QUANTITY as actualQuantity, ip.ACTUAL_DATE as actualDate, ip.REMARKS as remarks, ip.COMPLETE_TIME as completeTime, ip.COMPLETE_USER as completeUser, ip.DELETED_YN as deletedYn FROM TBL_INBOUND_PRODUCT ip LEFT JOIN TBL_AGENCY_M a ON ip.AGNT_CD = a.AGNT_CD AND ip.CMPY_CD = a.CMPY_CD WHERE (ip.DELETED_YN IS NULL OR ip.DELETED_YN = 'N') AND ip.INBOUND_STATUS = 'COMPLETED'
AND ip.CMPY_CD = #{cmpyCd}
AND ip.AGNT_CD = #{agntCd}
AND ip.MTRL_CD LIKE '%' + #{mtrlCd} + '%'
AND ip.MTRL_NM LIKE '%' + #{mtrlNm} + '%'
AND CONVERT(DATE, ip.SAVE_TIME) >= #{dateFrom}
AND CONVERT(DATE, ip.SAVE_TIME) <= #{dateTo}
ORDER BY ip.SAVE_TIME DESC OFFSET (#{pageNum} - 1) * #{pageSize} ROWS FETCH NEXT #{pageSize} ROWS ONLY

SELECT COUNT(*)
FROM TBL_INBOUND_PRODUCT ip
LEFT JOIN TBL_AGENCY_M a ON ip.AGNT_CD = a.AGNT_CD AND ip.CMPY_CD = a.CMPY_CD
WHERE (ip.DELETED_YN IS NULL OR ip.DELETED_YN = 'N')
AND ip.INBOUND_STATUS = 'COMPLETED'

    AND ip.CMPY_CD = #{cmpyCd}


    AND ip.AGNT_CD = #{agntCd}


    AND ip.MTRL_CD LIKE '%' + #{mtrlCd} + '%'


    AND ip.MTRL_NM LIKE '%' + #{mtrlNm} + '%'


    AND CONVERT(DATE, ip.SAVE_TIME) >= #{dateFrom}


    AND CONVERT(DATE, ip.SAVE_TIME) <= #{dateTo}
